package ua.university.sms.controller;
import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import ua.university.sms.model.dto.TeacherDtos.*;import ua.university.sms.service.TeacherService;import java.util.*;
@RestController @RequestMapping("/api/teachers") public class TeacherController{private final TeacherService service;public TeacherController(TeacherService service){this.service=service;}@PostMapping public ResponseEntity<Response> create(@Valid @RequestBody Request r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));}@GetMapping("/{id}") public Response get(@PathVariable Long id){return service.get(id);}@GetMapping public List<Response> list(){return service.list();}@PutMapping("/{id}") public Response update(@PathVariable Long id,@Valid @RequestBody Request r){return service.update(id,r);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable Long id){service.delete(id);}}
